const crypto = require('crypto');
const headers = $input.item.json.headers || {};
const rawBody = $input.item.json.rawBody;
let bodyString = '';
if (Buffer.isBuffer(rawBody)) bodyString = rawBody.toString('utf8');
else if (typeof rawBody === 'string') bodyString = rawBody;
else bodyString = JSON.stringify($input.item.json.body || $input.item.json);

const sigHeader = headers['x-zoho-sign-signature'] || headers['X-Zoho-Sign-Signature'] || headers['x-zoho-webhook-signature'] || '';
const secret = process.env.ZOHO_SIGN_WEBHOOK_SECRET || '';
let verified = false;
if (secret && sigHeader) {
  try {
    const computed = crypto.createHmac('sha256', secret).update(bodyString).digest('hex');
    verified = (computed === sigHeader);
  } catch (e) { verified = false; }
} else if (!secret) {
  // Allow but flag — Mary should set secret before going live.
  verified = true;
}
if (!verified) return { json: { _unauthorized: true, error: 'invalid zoho signature' } };

let payload = null;
try { payload = JSON.parse(bodyString); } catch (e) { payload = $input.item.json.body || {}; }

// Zoho Sign payload shape: { request_status, requests: { request_id, document_ids, ... } }
const eventType = payload.event_type || payload.notification_type || (payload.requests && payload.requests.request_status) || '';
const req = payload.requests || payload;
const envelopeId = req.request_id || req.id || null;
const documentIds = (req.document_ids && req.document_ids.map(function (d) { return d.document_id || d; })) || [];
const declineReason = req.decline_reason || (req.actions && req.actions[0] && req.actions[0].decline_reason) || null;

if (!envelopeId) return { json: { _bad: true, error: 'no envelope id in payload', event_type: eventType } };

return { json: {
  _ok: true,
  event_type: eventType,
  envelope_id: envelopeId,
  document_ids: documentIds,
  decline_reason: declineReason
} };

const ctx = $('Verify Signature').item.json;
const rows = $input.item.json;
const d = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!d || !d.id) return { json: { _not_found: true, envelope_id: ctx.envelope_id } };

const evt = String(ctx.event_type || '').toLowerCase();
let kind = 'unknown';
if (evt.indexOf('completed') >= 0 || evt.indexOf('signed') >= 0) kind = 'signed';
else if (evt.indexOf('declined') >= 0 || evt.indexOf('rejected') >= 0) kind = 'declined';
else if (evt.indexOf('expired') >= 0) kind = 'expired';

return { json: {
  disclosure_id: d.id,
  client_id: d.client_id,
  disclosure_type: d.disclosure_type,
  envelope_id: ctx.envelope_id,
  kind: kind,
  decline_reason: ctx.decline_reason
} };
